//
// cif2omx.c
//
// Released by T. Ozaki, Feb. 21, 2026
//
// A lightweight CIF (CIF 1.1 style) parser that supports:
// - loop_ data split across multiple lines
// - quoted strings (single/double) with spaces
// - semicolon-started multiline text fields
// - atomic coordinates given in either fractional (_atom_site_fract_*) or Cartesian (_atom_site_Cartn_*)
// It also writes a minimal OpenMX input file similar to OpenMX Viewer.
//
//
// NOTE: This file embeds the full space-group database used in cif.js:
//       - DB_spacegroup: mapping between IT number / HM / Hall
//       - DB_voperation_xyz: mapping Hall -> list of symmetry operations (xyz strings)
//       If explicit operators are present in the CIF, those are used.
//       Otherwise, symmetry operators are filled from the embedded DB using Hall/HM/number.
//
// Build: gcc -std=c99 -O2 -Wall -Wextra -pedantic cif2omx.c -o cif2omx -lm -o cif2openmx -lm

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <math.h>
#include <getopt.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846264338327950288
#endif

/* Default values for the autogenerated SCF block.
   scf.Kgrid follows OpenMX Viewer save_files.js: use reciprocal vectors
   including 2*pi and Nk_i = floor(|b_i|/d), with default d = 0.33 (1/Ang).
   This is independent of Band.kpath, whose segment spacing stays d = 0.006
   with reciprocal vectors without 2*pi, matching the Viewer implementation. */
#define CIF2OMX_DEFAULT_KSPACING 0.33 
#define CIF2OMX_DEFAULT_ENERGYCUTOFF 220.0

/*========================
  Small utilities
========================*/

static void *xmalloc(size_t n){
  void *p = malloc(n ? n : 1);
  if (!p){ fprintf(stderr, "Out of memory\n"); exit(1); }
  return p;
}
static void *xrealloc(void *p, size_t n){
  void *q = realloc(p, n ? n : 1);
  if (!q){ fprintf(stderr, "Out of memory\n"); exit(1); }
  return q;
}
static char *xstrdup(const char *s){
  size_t n = strlen(s);
  char *p = (char*)xmalloc(n+1);
  memcpy(p, s, n+1);
  return p;
}

static int str_ieq(const char *a, const char *b){
  while (*a && *b){
    if (tolower((unsigned char)*a) != tolower((unsigned char)*b)) return 0;
    a++; b++;
  }
  return *a==0 && *b==0;
}
static int str_istarts(const char *a, const char *prefix){
  while (*prefix){
    if (!*a) return 0;
    if (tolower((unsigned char)*a) != tolower((unsigned char)*prefix)) return 0;
    a++; prefix++;
  }
  return 1;
}

static void str_to_lower_inplace(char *s){
  for (; *s; s++) *s = (char)tolower((unsigned char)*s);
}

static double wrap01(double x){
  double y = x - floor(x);
  /* guard for -0.0 */
  if (y < 0.0) y += 1.0;
  if (y >= 1.0) y -= 1.0;
  return y;
}

/* CIF numeric fields sometimes look like: 0.123(4) or 1/2 */
static double parse_cif_number(const char *s, int *ok){
  *ok = 0;
  if (!s || !*s) return 0.0;

  /* remove uncertainty part "(...)" */
  char buf[256];
  size_t n = 0;
  for (const char *p=s; *p && n+1<sizeof(buf); p++){
    if (*p=='(') break;
    buf[n++] = *p;
  }
  buf[n] = 0;

  /* trim */
  while (n>0 && isspace((unsigned char)buf[n-1])) buf[--n]=0;
  size_t i=0; while (buf[i] && isspace((unsigned char)buf[i])) i++;
  if (i>0) memmove(buf, buf+i, strlen(buf+i)+1);

  if (buf[0]=='.' && buf[1]==0) { *ok=1; return NAN; } /* '.' means missing */
  if (buf[0]=='?' && buf[1]==0) { *ok=1; return NAN; } /* '?' means unknown */

  /* fraction a/b */
  char *slash = strchr(buf, '/');
  if (slash){
    *slash = 0;
    char *end1=NULL, *end2=NULL;
    double a = strtod(buf, &end1);
    double b = strtod(slash+1, &end2);
    if (end1 && *end1==0 && end2 && *end2==0 && b!=0.0){
      *ok = 1;
      return a/b;
    }
    return 0.0;
  }

  char *end=NULL;
  double v = strtod(buf, &end);
  if (end && *end==0){
    *ok = 1;
    return v;
  }
  return 0.0;
}

/*========================
  Tokenizer for CIF
========================*/

typedef enum {
  TOK_EOF = 0,
  TOK_WORD = 1,
  TOK_TEXT = 2
} TokenType;

typedef struct {
  TokenType type;
  char *s;          /* token string (malloc'ed) */
  int line;         /* 1-based line number */
} Token;

typedef struct {
  char *buf;
  size_t len;
  size_t pos;
  int line;
  int bol;          /* beginning-of-line flag */
  int has_push;
  Token push;
} Tokenizer;

static char *read_all(FILE *fp, size_t *out_len){
  size_t cap = 1<<20;
  size_t len = 0;
  char *buf = (char*)xmalloc(cap);
  for (;;){
    size_t want = cap - len;
    if (want < 4096){
      cap *= 2;
      buf = (char*)xrealloc(buf, cap);
      want = cap - len;
    }
    size_t n = fread(buf+len, 1, want, fp);
    len += n;
    if (n==0){
      if (ferror(fp)){
        fprintf(stderr, "I/O error while reading CIF\n");
        free(buf);
        return NULL;
      }
      break;
    }
  }
  buf = (char*)xrealloc(buf, len+1);
  buf[len] = 0;
  if (out_len) *out_len = len;
  return buf;
}

static void tokenizer_init(Tokenizer *tz, FILE *fp){
  memset(tz, 0, sizeof(*tz));
  tz->buf = read_all(fp, &tz->len);
  tz->pos = 0;
  tz->line = 1;
  tz->bol = 1;
  tz->has_push = 0;
}

static void token_free(Token *t){
  if (t && t->s){
    free(t->s);
    t->s = NULL;
  }
}

static int tz_peek(Tokenizer *tz){
  if (tz->pos >= tz->len) return EOF;
  return (unsigned char)tz->buf[tz->pos];
}

static int tz_getc(Tokenizer *tz){
  if (tz->pos >= tz->len) return EOF;
  int c = (unsigned char)tz->buf[tz->pos++];
  if (c=='\n'){
    tz->line++;
    tz->bol = 1;
  } else {
    tz->bol = 0;
  }
  return c;
}

static void tz_ungetc(Tokenizer *tz){
  if (tz->pos==0) return;
  tz->pos--;
  int c = (unsigned char)tz->buf[tz->pos];
  /* conservative: recompute bol */
  if (c=='\n'){
    /* stepping back over newline sets bol unknown; set bol=0 and accept
       since we only need exact bol when we read ';' in column 1. */
    tz->line--;
    tz->bol = 0;
  } else {
    tz->bol = 0;
  }
}

static void skip_space_and_comments(Tokenizer *tz){
  for (;;){
    int c = tz_peek(tz);
    if (c==EOF) return;

    /* whitespace */
    if (c==' ' || c=='\t' || c=='\r' || c=='\n'){
      tz_getc(tz);
      continue;
    }

    /* comment: '#' to end of line (only if not in text field) */
    if (c=='#'){
      while ((c = tz_getc(tz)) != EOF && c!='\n'){}
      continue;
    }

    return;
  }
}

static char *read_quoted(Tokenizer *tz, int quote){
  /* quote already consumed */
  size_t cap=256, len=0;
  char *out = (char*)xmalloc(cap);
  for (;;){
    int c = tz_getc(tz);
    if (c==EOF){
      break;
    }
    if (c==quote){
      /* CIF convention: doubled quote inside same quote string => literal quote */
      int c2 = tz_peek(tz);
      if (c2==quote){
        tz_getc(tz);
        c = quote;
      } else {
        break;
      }
    }
    if (c=='\\'){ /* permissive: allow backslash escape */
      int n = tz_peek(tz);
      if (n==quote || n=='\\'){
        tz_getc(tz);
        c = n;
      }
    }
    if (len+2>cap){
      cap*=2;
      out = (char*)xrealloc(out, cap);
    }
    out[len++] = (char)c;
  }
  out[len]=0;
  return out;
}

static char *read_unquoted(Tokenizer *tz){
  size_t cap=256, len=0;
  char *out = (char*)xmalloc(cap);
  for (;;){
    int c = tz_peek(tz);
    if (c==EOF) break;
    if (c==' ' || c=='\t' || c=='\r' || c=='\n') break;
    if (c=='#'){ /* treat as comment start only if separated by whitespace; here it is in-token */
      /* keep it as part of token */
    }
    c = tz_getc(tz);
    if (len+2>cap){
      cap*=2;
      out = (char*)xrealloc(out, cap);
    }
    out[len++] = (char)c;
  }
  out[len]=0;
  return out;
}

static char *read_textfield(Tokenizer *tz){
  /* We are at ';' and tz->bol == 1 (beginning of line) BEFORE consuming ';' */
  /* Consume the leading ';' */
  int c = tz_getc(tz);
  (void)c;

  /* Read until a line that begins with ';' (column 1) */
  size_t cap=512, len=0;
  char *out = (char*)xmalloc(cap);
  for (;;){
    int p = tz_peek(tz);
    if (p==EOF) break;

    /* detect terminator: ';' at BOL */
    if (tz->bol && p==';'){
      tz_getc(tz); /* consume ';' */
      /* consume the rest of the terminator line (usually newline) */
      while ((p = tz_peek(tz)) != EOF && p!='\n') tz_getc(tz);
      if (p=='\n') tz_getc(tz);
      break;
    }

    int ch = tz_getc(tz);
    if (ch==EOF) break;
    if (len+2>cap){
      cap*=2;
      out = (char*)xrealloc(out, cap);
    }
    out[len++] = (char)ch;
  }
  out[len]=0;

  /* CIF text field includes the leading newline after the opening ';' if present.
     Many consumers keep it; OpenMX Viewer doesn't use text fields for structure, so
     we simply keep raw content. */
  return out;
}

static Token next_token(Tokenizer *tz){
  Token t; memset(&t, 0, sizeof(t));
  if (tz->has_push){
    tz->has_push = 0;
    return tz->push;
  }

  skip_space_and_comments(tz);
  t.line = tz->line;
  int c = tz_peek(tz);
  if (c==EOF){
    t.type = TOK_EOF;
    t.s = NULL;
    return t;
  }

  /* semicolon text field: only if ';' is at column 1 (BOL) */
  if (tz->bol && c==';'){
    t.type = TOK_TEXT;
    t.s = read_textfield(tz);
    return t;
  }

  c = tz_getc(tz);
  if (c=='\'' || c=='"'){
    t.type = TOK_WORD;
    t.s = read_quoted(tz, c);
    return t;
  }

  /* unquoted word: c already consumed */
  tz_ungetc(tz);
  t.type = TOK_WORD;
  t.s = read_unquoted(tz);
  return t;
}

static void push_token(Tokenizer *tz, Token *t){
  if (tz->has_push){
    fprintf(stderr, "Internal error: token push overflow\n");
    exit(1);
  }
  tz->has_push = 1;
  tz->push = *t;
  /* caller must not free */
}

/*========================
  Minimal CIF model
========================*/

typedef struct {
  char *label;
  char *symbol;
  double fract[3];
  double cartn[3];
  int has_fract;
  int has_cartn;
  double occ;
} AtomSite;

typedef struct {
  double a,b,c;
  double alpha,beta,gamma;
  int has_lengths;
  int has_angles;
  int has_cell;
  double tv[3][3]; /* lattice vectors (Angstrom) */
  int has_tv;
} Cell;

typedef struct {
  AtomSite *vatom;
  int natom, cap_atom;

  char **vop_xyz;
  int nop, cap_op;

  /* Space-group identifiers (may be absent). */
  int spg_number;      /* International Tables number (1..230) or 0 */
  char *spg_HM;        /* Hermann-Mauguin (as in cif.js DB_spacegroup[].HM) */
  char *spg_Hall;      /* Hall symbol */

  Cell cell;
  char *data_name;
} CIF;


/*========================
  Space-group database (from cif.js)
  - DB_spacegroup: mapping between IT number / HM / Hall
  - DB_voperation_xyz: mapping Hall -> list of symmetry operations in xyz strings
========================*/

typedef struct {
  int number;
  const char *HM;
  const char *Hall;
  const char *shape;
  const char *center;
  int uniq;
} SpaceGroup;

typedef struct {
  const char *Hall;
  const char *const *ops;
  int nops;
} VOperation;

