static const SpaceGroup *SpaceGroup_findByNumber(int number){
  for (size_t i=0;i<sizeof(DB_spacegroup)/sizeof(DB_spacegroup[0]);i++){
    if (DB_spacegroup[i].number == number) return &DB_spacegroup[i];
  }
  return NULL;
}
static const SpaceGroup *SpaceGroup_findByHM(const char *HM){
  if (!HM || !*HM) return NULL;
  for (size_t i=0;i<sizeof(DB_spacegroup)/sizeof(DB_spacegroup[0]);i++){
    if (str_ieq(DB_spacegroup[i].HM, HM)) return &DB_spacegroup[i];
  }
  return NULL;
}
static const SpaceGroup *SpaceGroup_findByHall(const char *Hall){
  if (!Hall || !*Hall) return NULL;
  for (size_t i=0;i<sizeof(DB_spacegroup)/sizeof(DB_spacegroup[0]);i++){
    if (strcmp(DB_spacegroup[i].Hall, Hall)==0) return &DB_spacegroup[i];
  }
  return NULL;
}

static const char *const *Operation_find(const char *Hall, int *out_nops){
  if (out_nops) *out_nops = 0;
  if (!Hall || !*Hall) return NULL;
  for (size_t i=0;i<sizeof(DB_voperation_xyz)/sizeof(DB_voperation_xyz[0]);i++){
    if (strcmp(DB_voperation_xyz[i].Hall, Hall)==0){
      if (out_nops) *out_nops = DB_voperation_xyz[i].nops;
      return DB_voperation_xyz[i].ops;
    }
  }
  return NULL;
}


