typedef struct {
  int rot[3][3];
  double tr[3];
} SymOp;

static int parse_symop_term(const char *term, int sign, int v[3], double *t){
  /* term may be x, y, z, fraction, decimal, or 1/2 etc */
  if (term[0]==0) return 1;

  if (strlen(term)==1 && (term[0]=='x' || term[0]=='y' || term[0]=='z')){
    int idx = term[0]-'x';
    v[idx] += sign;
    return 1;
  }

  /* allow forms like "1/2", "2", "0.25" */
  int ok=0;
  double val = parse_cif_number(term, &ok);
  if (!ok) return 0;
  if (isnan(val)) return 1;
  *t += sign*val;
  return 1;
}

static int parse_symop_expr(const char *expr_in, int row[3], double *t){
  /* Parse expression for one coordinate, e.g. "-x+y+1/2" */
  char *expr = xstrdup(expr_in);
  /* remove spaces */
  size_t w=0;
  for (size_t r=0; expr[r]; r++){
    if (!isspace((unsigned char)expr[r])) expr[w++] = expr[r];
  }
  expr[w]=0;

  row[0]=row[1]=row[2]=0;
  *t = 0.0;

  int sign = +1;
  size_t i=0;
  while (expr[i]){
    if (expr[i]=='+'){ sign=+1; i++; continue; }
    if (expr[i]=='-'){ sign=-1; i++; continue; }

    /* read term until + or - */
    size_t j=i;
    while (expr[j] && expr[j] != '+' && expr[j] != '-') j++;
    char save = expr[j];
    expr[j] = 0;

    int ok = parse_symop_term(expr+i, sign, row, t);

    expr[j] = save;
    if (!ok){ free(expr); return 0; }
    i = j;
  }

  /* CIF uses modulo 1 translations */
  *t = wrap01(*t);

  free(expr);
  return 1;
}

static int parse_symop_xyz(const char *xyz, SymOp *op){
  /* xyz example: "x,y,z" or "-x+1/2,y+1/2,z" */
  char *s = xstrdup(xyz);

  /* strip quotes if any */
  size_t n = strlen(s);
  if (n>=2 && ((s[0]=='\'' && s[n-1]=='\'') || (s[0]=='"' && s[n-1]=='"'))){
    s[n-1]=0;
    memmove(s, s+1, n-1);
  }

  /* split by commas */
  char *p1 = strchr(s, ',');
  if (!p1){ free(s); return 0; }
  *p1++ = 0;
  char *p2 = strchr(p1, ',');
  if (!p2){ free(s); return 0; }
  *p2++ = 0;

  const char *expr[3] = { s, p1, p2 };
  for (int i=0;i<3;i++){
    int row[3]; double t;
    if (!parse_symop_expr(expr[i], row, &t)){ free(s); return 0; }
    for (int j=0;j<3;j++) op->rot[i][j] = row[j];
    op->tr[i] = t;
  }

  /* Basic sanity checks: rotation entries in {-1,0,1} and det = +/-1.
     NOTE: many space groups have two non-zeros per row (e.g. x-y), so we must NOT
     assume a permutation matrix. */
  for (int i=0;i<3;i++){
    int nz=0;
    for (int j=0;j<3;j++){
      if (op->rot[i][j] < -1 || op->rot[i][j] > 1){ free(s); return 0; }
      if (op->rot[i][j] != 0) nz++;
    }
    if (nz==0){ free(s); return 0; }
  }

  int a=op->rot[0][0], b=op->rot[0][1], c=op->rot[0][2];
  int d=op->rot[1][0], e=op->rot[1][1], f=op->rot[1][2];
  int g=op->rot[2][0], h=op->rot[2][1], i=op->rot[2][2];
  int det = a*(e*i - f*h) - b*(d*i - f*g) + c*(d*h - e*g);
  if (!(det==1 || det==-1)){ free(s); return 0; }

  free(s);
  return 1;
}

/*========================
  Cell / coordinate math
========================*/

static void cross3(const double a[3], const double b[3], double c[3]){
  c[0] = a[1]*b[2]-a[2]*b[1];
  c[1] = a[2]*b[0]-a[0]*b[2];
  c[2] = a[0]*b[1]-a[1]*b[0];
}
static double dot3(const double a[3], const double b[3]){
  return a[0]*b[0]+a[1]*b[1]+a[2]*b[2];
}

static int inv3(const double m[3][3], double inv[3][3]){
  /* Compute inverse of 3x3 matrix. Return 0 if singular. */
  double a=m[0][0], b=m[0][1], c=m[0][2];
  double d=m[1][0], e=m[1][1], f=m[1][2];
  double g=m[2][0], h=m[2][1], i=m[2][2];

  double A =  (e*i - f*h);
  double B = -(d*i - f*g);
  double C =  (d*h - e*g);
  double D = -(b*i - c*h);
  double E =  (a*i - c*g);
  double F = -(a*h - b*g);
  double G =  (b*f - c*e);
  double H = -(a*f - c*d);
  double I =  (a*e - b*d);

  double det = a*A + b*B + c*C;
  if (fabs(det) < 1e-14) return 0;

  double id = 1.0/det;
  inv[0][0] = A*id; inv[0][1] = D*id; inv[0][2] = G*id;
  inv[1][0] = B*id; inv[1][1] = E*id; inv[1][2] = H*id;
  inv[2][0] = C*id; inv[2][1] = F*id; inv[2][2] = I*id;
  return 1;
}

static void matvec3(const double (*m)[3], const double v[3], double out[3]){
  out[0] = m[0][0]*v[0] + m[0][1]*v[1] + m[0][2]*v[2];
  out[1] = m[1][0]*v[0] + m[1][1]*v[1] + m[1][2]*v[2];
  out[2] = m[2][0]*v[0] + m[2][1]*v[1] + m[2][2]*v[2];
}

static int build_tv_from_lengths_angles(Cell *cell){
  if (!cell->has_lengths || !cell->has_angles) return 0;

  double a = cell->a;
  double b = cell->b;
  double c = cell->c;
  double alpha = cell->alpha * M_PI/180.0;
  double beta  = cell->beta  * M_PI/180.0;
  double gamma = cell->gamma * M_PI/180.0;

  double cosA = cos(alpha), cosB = cos(beta), cosG = cos(gamma);
  double sinG = sin(gamma);

  if (fabs(sinG) < 1e-14) return 0;

  /* Standard crystallographic convention */
  cell->tv[0][0] = a;  cell->tv[0][1] = 0.0;         cell->tv[0][2] = 0.0;
  cell->tv[1][0] = b*cosG; cell->tv[1][1] = b*sinG; cell->tv[1][2] = 0.0;

  double cx = c*cosB;
  double cy = c*(cosA - cosB*cosG)/sinG;
  double cz2 = c*c - cx*cx - cy*cy;
  double cz = (cz2 > 0.0) ? sqrt(cz2) : 0.0;

  cell->tv[2][0] = cx; cell->tv[2][1] = cy; cell->tv[2][2] = cz;

  cell->has_tv = 1;
  cell->has_cell = 1;
  return 1;
}

static void frac_to_cart(const double tv[3][3], const double f[3], double r[3]){
  /* r = f0*a + f1*b + f2*c */
  r[0] = f[0]*tv[0][0] + f[1]*tv[1][0] + f[2]*tv[2][0];
  r[1] = f[0]*tv[0][1] + f[1]*tv[1][1] + f[2]*tv[2][1];
  r[2] = f[0]*tv[0][2] + f[1]*tv[1][2] + f[2]*tv[2][2];
}

static int cart_to_frac(const double tv[3][3], const double r[3], double f[3]){
  double invtv[3][3];
  if (!inv3(tv, invtv)) return 0;
  matvec3((const double (*)[3])invtv, r, f);
  return 1;
}

/*========================
  CIF parsing
========================*/

static void cif_init(CIF *cif){
  memset(cif, 0, sizeof(*cif));
  cif->cell.a = cif->cell.b = cif->cell.c = NAN;
  cif->cell.alpha = cif->cell.beta = cif->cell.gamma = NAN;
}

static void cif_free(CIF *cif){
  if (!cif) return;
  for (int i=0;i<cif->natom;i++){
    free(cif->vatom[i].label);
    free(cif->vatom[i].symbol);
  }
  free(cif->vatom);
  for (int i=0;i<cif->nop;i++) free(cif->vop_xyz[i]);
  free(cif->vop_xyz);
  free(cif->spg_HM);
  free(cif->spg_Hall);
  free(cif->data_name);
  memset(cif, 0, sizeof(*cif));
}

static void cif_add_atom(CIF *cif, const AtomSite *a){
  if (cif->natom == cif->cap_atom){
    cif->cap_atom = cif->cap_atom ? cif->cap_atom*2 : 64;
    cif->vatom = (AtomSite*)xrealloc(cif->vatom, sizeof(AtomSite)*cif->cap_atom);
  }
  cif->vatom[cif->natom++] = *a;
}

static void cif_add_op(CIF *cif, const char *opxyz){
  if (cif->nop == cif->cap_op){
    cif->cap_op = cif->cap_op ? cif->cap_op*2 : 64;
    cif->vop_xyz = (char**)xrealloc(cif->vop_xyz, sizeof(char*)*cif->cap_op);
  }
  cif->vop_xyz[cif->nop++] = xstrdup(opxyz);
}

static int is_kw_terminator(const char *s){
  return str_istarts(s, "data_") || str_istarts(s, "save_") ||
         str_ieq(s, "loop_") || str_ieq(s, "stop_") || str_ieq(s, "global_");
}

static int col_is_atom(const char *c){
  return str_istarts(c, "_atom_site_");
}
static int col_is_symop(const char *c){
  return str_ieq(c, "_symmetry_equiv_pos_as_xyz") ||
         str_ieq(c, "_space_group_symop_operation_xyz") ||
         str_ieq(c, "_symmetry_equiv_pos_as_xyz."); /* tolerant */
}

static int parse_loop(Tokenizer *tz, CIF *cif){
  /* Collect column names (tags) */
  int ncol=0, cap=16;
  char **col = (char**)xmalloc(sizeof(char*)*cap);

  for (;;){
    Token t = next_token(tz);
    if (t.type==TOK_EOF){ token_free(&t); break; }

    if (t.type!=TOK_WORD){
      token_free(&t);
      continue;
    }

    if (t.s[0]=='_'){
      if (ncol==cap){
        cap*=2;
        col = (char**)xrealloc(col, sizeof(char*)*cap);
      }
      /* store lowercase tag name for matching */
      char *name = xstrdup(t.s);
      str_to_lower_inplace(name);
      col[ncol++] = name;
      token_free(&t);
      continue;
    }

    /* first value -> start reading data */
    push_token(tz, &t);
    break;
  }

  if (ncol==0){
    free(col);
    return 1; /* nothing to do */
  }

  int is_atom_loop = 0;
  int is_symop_loop = 0;
  for (int i=0;i<ncol;i++){
    if (col_is_atom(col[i])) is_atom_loop = 1;
    if (col_is_symop(col[i])) is_symop_loop = 1;
  }

  /* Column indices for atom_site */
  int idx_label=-1, idx_symbol=-1;
  int idx_fx=-1, idx_fy=-1, idx_fz=-1;
  int idx_cx=-1, idx_cy=-1, idx_cz=-1;
  int idx_occ=-1;

  if (is_atom_loop){
    for (int i=0;i<ncol;i++){
      if (str_ieq(col[i], "_atom_site_label")) idx_label = i;
      else if (str_ieq(col[i], "_atom_site_type_symbol")) idx_symbol = i;
      else if (str_ieq(col[i], "_atom_site_fract_x")) idx_fx = i;
      else if (str_ieq(col[i], "_atom_site_fract_y")) idx_fy = i;
      else if (str_ieq(col[i], "_atom_site_fract_z")) idx_fz = i;
      else if (str_ieq(col[i], "_atom_site_cartn_x") || str_ieq(col[i], "_atom_site_cartn_x_esd")) idx_cx = i;
      else if (str_ieq(col[i], "_atom_site_cartn_y") || str_ieq(col[i], "_atom_site_cartn_y_esd")) idx_cy = i;
      else if (str_ieq(col[i], "_atom_site_cartn_z") || str_ieq(col[i], "_atom_site_cartn_z_esd")) idx_cz = i;
      else if (str_ieq(col[i], "_atom_site_occupancy")) idx_occ = i;
    }
  }

  int idx_op=-1;
  if (is_symop_loop){
    for (int i=0;i<ncol;i++){
      if (col_is_symop(col[i])) idx_op = i;
    }
  }

  /* Read values until termination */
  char **row = (char**)xmalloc(sizeof(char*)*ncol);
  int nrow=0;

  for (;;){
    Token t = next_token(tz);
    if (t.type==TOK_EOF){
      token_free(&t);
      break;
    }
    if (t.type==TOK_WORD){
      char *low = xstrdup(t.s);
      str_to_lower_inplace(low);
      int term = (t.s[0]=='_') || is_kw_terminator(low);
      free(low);
      if (term){
        push_token(tz, &t);
        break;
      }
    }

    /* This is a value token */
    row[0] = xstrdup(t.s ? t.s : "");
    token_free(&t);

    for (int k=1;k<ncol;k++){
      Token u = next_token(tz);
      if (u.type==TOK_EOF){
        token_free(&u);
        fprintf(stderr, "CIF loop row ended early at line %d (need %d columns)\n", tz->line, ncol);
        goto fail;
      }
      if (u.type==TOK_WORD){
        char *low2 = xstrdup(u.s);
        str_to_lower_inplace(low2);
        int term2 = (u.s[0]=='_') || is_kw_terminator(low2);
        free(low2);
        if (term2){
          token_free(&u);
          fprintf(stderr, "CIF loop row ended early at line %d (need %d columns)\n", tz->line, ncol);
          goto fail;
        }
      }
      row[k] = xstrdup(u.s ? u.s : "");
      token_free(&u);
    }

    /* Process row */
    if (is_symop_loop && idx_op>=0){
      cif_add_op(cif, row[idx_op]);
    }

    if (is_atom_loop){
      AtomSite a; memset(&a, 0, sizeof(a));
      a.label = (idx_label>=0) ? xstrdup(row[idx_label]) : NULL;
      a.symbol = (idx_symbol>=0) ? xstrdup(row[idx_symbol]) : NULL;
      a.occ = 1.0;

      if (!a.symbol && a.label){
        /* fallback: take leading letters from label */
        char tmp[16]={0};
        size_t m=0;
        while (a.label[m] && m<2 && isalpha((unsigned char)a.label[m])){
          tmp[m] = a.label[m];
          m++;
        }
        tmp[m]=0;
        a.symbol = xstrdup(tmp);
      }

      /* normalize symbol case: first upper, rest lower */
      if (a.symbol && a.symbol[0]){
        a.symbol[0] = (char)toupper((unsigned char)a.symbol[0]);
        for (size_t p=1; a.symbol[p]; p++){
          a.symbol[p] = (char)tolower((unsigned char)a.symbol[p]);
        }
      }

      int okx=0, oky=0, okz=0;

      if (idx_fx>=0 && idx_fy>=0 && idx_fz>=0){
        a.fract[0] = parse_cif_number(row[idx_fx], &okx);
        a.fract[1] = parse_cif_number(row[idx_fy], &oky);
        a.fract[2] = parse_cif_number(row[idx_fz], &okz);
        if (okx && oky && okz && !isnan(a.fract[0]) && !isnan(a.fract[1]) && !isnan(a.fract[2])){
          a.has_fract = 1;
        }
      }

      okx=oky=okz=0;
      if (idx_cx>=0 && idx_cy>=0 && idx_cz>=0){
        a.cartn[0] = parse_cif_number(row[idx_cx], &okx);
        a.cartn[1] = parse_cif_number(row[idx_cy], &oky);
        a.cartn[2] = parse_cif_number(row[idx_cz], &okz);
        if (okx && oky && okz && !isnan(a.cartn[0]) && !isnan(a.cartn[1]) && !isnan(a.cartn[2])){
          a.has_cartn = 1;
        }
      }

      if (idx_occ>=0){
        int ok=0;
        double occ = parse_cif_number(row[idx_occ], &ok);
        if (ok && !isnan(occ)) a.occ = occ;
      }

      if (!a.has_fract && !a.has_cartn){
        /* still store it to let caller decide; but warn */
        fprintf(stderr, "Warning: atom_site row has no usable coordinates (line %d)\n", tz->line);
      }

      cif_add_atom(cif, &a);
    }

    for (int k=0;k<ncol;k++) free(row[k]);
    nrow++;
  }

  free(row);
  for (int i=0;i<ncol;i++) free(col[i]);
  free(col);
  return 1;

fail:
  for (int k=0;k<ncol;k++) free(row[k]);
  free(row);
  for (int i=0;i<ncol;i++) free(col[i]);
  free(col);
  return 0;
}

static int parse_tag_value(Tokenizer *tz, CIF *cif, const char *tag){
  Token v = next_token(tz);
  if (v.type==TOK_EOF){
    token_free(&v);
    return 0;
  }
  /* We only need a few tags */
  if (str_ieq(tag, "_cell_length_a")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.a=x; cif->cell.has_lengths=1; }
  } else if (str_ieq(tag, "_cell_length_b")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.b=x; cif->cell.has_lengths=1; }
  } else if (str_ieq(tag, "_cell_length_c")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.c=x; cif->cell.has_lengths=1; }
  } else if (str_ieq(tag, "_cell_angle_alpha")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.alpha=x; cif->cell.has_angles=1; }
  } else if (str_ieq(tag, "_cell_angle_beta")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.beta=x; cif->cell.has_angles=1; }
  } else if (str_ieq(tag, "_cell_angle_gamma")){
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){ cif->cell.gamma=x; cif->cell.has_angles=1; }

  } else if (str_ieq(tag, "_space_group_it_number") ||
             str_ieq(tag, "_symmetry_int_tables_number") ||
             str_ieq(tag, "_symmetry_space_group_number")){
    /* Space-group number (International Tables) */
    int ok=0; double x=parse_cif_number(v.s, &ok);
    if (ok && !isnan(x)){
      int n = (int)llround(x);
      if (1<=n && n<=230) cif->spg_number = n;
    }
  } else if (str_ieq(tag, "_space_group_name_h-m_alt") ||
             str_ieq(tag, "_symmetry_space_group_name_h-m")){
    /* Hermann-Mauguin symbol (OpenMX Viewer strips all whitespaces) */
    free(cif->spg_HM);
    cif->spg_HM = xstrdup(v.s ? v.s : "");
    /* remove all whitespaces */
    if (cif->spg_HM){
      size_t w=0;
      for (size_t r=0; cif->spg_HM[r]; r++){
        if (!isspace((unsigned char)cif->spg_HM[r])) cif->spg_HM[w++] = cif->spg_HM[r];
      }
      cif->spg_HM[w]=0;
    }
  } else if (str_ieq(tag, "_space_group_name_hall") ||
             str_ieq(tag, "_symmetry_space_group_name_hall")){
    /* Hall symbol (OpenMX Viewer trims head/tail) */
    free(cif->spg_Hall);
    cif->spg_Hall = xstrdup(v.s ? v.s : "");
    if (cif->spg_Hall){
      char *s = cif->spg_Hall;
      while (*s && isspace((unsigned char)*s)) s++;
      if (s != cif->spg_Hall) memmove(cif->spg_Hall, s, strlen(s)+1);
      size_t n = strlen(cif->spg_Hall);
      while (n>0 && isspace((unsigned char)cif->spg_Hall[n-1])) cif->spg_Hall[--n]=0;
    }

  } else if (str_istarts(tag, "data_")){
    /* not a tag, but handled elsewhere */
  } else if (str_ieq(tag, "_audit_creation_method")){
    /* ignore */
  } else if (str_ieq(tag, "_chemical_name_mineral") || str_ieq(tag, "_chemical_name_systematic")){
    /* ignore */
  }

  token_free(&v);
  return 1;
}


static void cif_try_fill_symops_from_db(CIF *cif){
  if (!cif) return;
  if (cif->nop > 0) return; /* already present in CIF */

  const SpaceGroup *spg = NULL;

  if (cif->spg_Hall && cif->spg_Hall[0]){
    spg = SpaceGroup_findByHall(cif->spg_Hall);
  }
  if (!spg && cif->spg_HM && cif->spg_HM[0]){
    spg = SpaceGroup_findByHM(cif->spg_HM);
  }
  if (!spg && cif->spg_number > 0){
    spg = SpaceGroup_findByNumber(cif->spg_number);
  }

  if (!spg) return;

  int nops = 0;
  const char *const *ops = Operation_find(spg->Hall, &nops);
  if (!ops || nops <= 0) return;

  /* Canonicalize stored identifiers to the DB values. */
  if (!cif->spg_Hall || strcmp(cif->spg_Hall, spg->Hall) != 0){
    free(cif->spg_Hall);
    cif->spg_Hall = xstrdup(spg->Hall);
  }
  if (!cif->spg_HM || strcmp(cif->spg_HM, spg->HM) != 0){
    free(cif->spg_HM);
    cif->spg_HM = xstrdup(spg->HM);
  }
  if (cif->spg_number == 0) cif->spg_number = spg->number;

  for (int i=0;i<nops;i++){
    cif_add_op(cif, ops[i]);
  }
}


static int cif_parse(FILE *fp, CIF *cif){
  Tokenizer tz;
  tokenizer_init(&tz, fp);
  if (!tz.buf) return 0;

  cif_init(cif);

  for (;;){
    Token t = next_token(&tz);
    if (t.type==TOK_EOF){ token_free(&t); break; }
    if (t.type!=TOK_WORD){ token_free(&t); continue; }

    char *low = xstrdup(t.s);
    str_to_lower_inplace(low);

    if (str_istarts(low, "data_")){
      free(cif->data_name);
      cif->data_name = xstrdup(t.s);
      token_free(&t);
      free(low);
      continue;
    }

    if (str_ieq(low, "loop_")){
      token_free(&t);
      free(low);
      if (!parse_loop(&tz, cif)){ free(tz.buf); return 0; }
      continue;
    }

    if (t.s[0]=='_'){
      /* tag-value */
      char *tag = xstrdup(t.s);
      str_to_lower_inplace(tag);
      token_free(&t);
      free(low);
      int ok = parse_tag_value(&tz, cif, tag);
      free(tag);
      if (!ok){ free(tz.buf); return 0; }
      continue;
    }

    /* otherwise ignore token */
    token_free(&t);
    free(low);
  }

  /* Construct lattice vectors */
  if (!build_tv_from_lengths_angles(&cif->cell)){
    fprintf(stderr, "Warning: failed to build lattice vectors from cell parameters.\n");
  }

  /* If symmetry operators are absent in CIF, try to expand from the embedded Hall database. */
  cif_try_fill_symops_from_db(cif);

  free(tz.buf);
  return 1;
}

/*========================
  Expand atoms using symmetry operations
========================*/

typedef struct {
  char symbol[8];
  double f[3];
  double r[3];
} AtomOut;

typedef struct {
  AtomOut *v;
  int n, cap;
  double tv[3][3];
  int has_tv;
} CIF_Result;

static void cif_result_init(CIF_Result *res){
  memset(res, 0, sizeof(*res));
}
void cif_result_free(CIF_Result *res){
  free(res->v);
  memset(res, 0, sizeof(*res));
}

static int atom_same(const AtomOut *a, const AtomOut *b, double eps){
  if (!str_ieq(a->symbol, b->symbol)) return 0;
  double dx = a->f[0]-b->f[0];
  double dy = a->f[1]-b->f[1];
  double dz = a->f[2]-b->f[2];
  /* consider PBC: choose minimum image in fractional space */
  dx -= round(dx);
  dy -= round(dy);
  dz -= round(dz);
  return fabs(dx)<eps && fabs(dy)<eps && fabs(dz)<eps;
}

static void result_add_unique(CIF_Result *res, const AtomOut *a, double eps){
  for (int i=0;i<res->n;i++){
    if (atom_same(&res->v[i], a, eps)) return;
  }
  if (res->n==res->cap){
    res->cap = res->cap ? res->cap*2 : 128;
    res->v = (AtomOut*)xrealloc(res->v, sizeof(AtomOut)*res->cap);
  }
  res->v[res->n++] = *a;
}

static int cif_expand_to_result(const CIF *cif, CIF_Result *res){
  cif_result_init(res);

  if (!cif->cell.has_tv){
    fprintf(stderr, "Error: lattice vectors are not available.\n");
    return 0;
  }
  memcpy(res->tv, cif->cell.tv, sizeof(res->tv));
  res->has_tv = 1;

  /* Build symmetry op list */
  SymOp *ops = NULL;
  int nop = 0;
  if (cif->nop > 0){
    ops = (SymOp*)xmalloc(sizeof(SymOp)*cif->nop);
    for (int i=0;i<cif->nop;i++){
      if (!parse_symop_xyz(cif->vop_xyz[i], &ops[nop])){
        fprintf(stderr, "Warning: failed to parse symmetry op: %s\n", cif->vop_xyz[i]);
        continue;
      }
      nop++;
    }
  }
  if (nop==0){
    /* identity only */
    ops = (SymOp*)xmalloc(sizeof(SymOp));
    memset(&ops[0], 0, sizeof(SymOp));
    for (int i=0;i<3;i++) ops[0].rot[i][i] = 1;
    nop = 1;
  }

  /* Expand atoms */
  const double eps = 1e-6;

  for (int ia=0; ia<cif->natom; ia++){
    const AtomSite *a = &cif->vatom[ia];
    if (!a->symbol || !a->symbol[0]) continue;

    double f0[3] = {0,0,0};
    if (a->has_fract){
      f0[0] = a->fract[0];
      f0[1] = a->fract[1];
      f0[2] = a->fract[2];
    } else if (a->has_cartn){
      if (!cart_to_frac(cif->cell.tv, a->cartn, f0)){
        fprintf(stderr, "Error: failed to invert lattice for Cartesian->fractional.\n");
        free(ops);
        return 0;
      }
    } else {
      continue;
    }

    /* wrap base fractional */
    f0[0]=wrap01(f0[0]); f0[1]=wrap01(f0[1]); f0[2]=wrap01(f0[2]);

    for (int io=0; io<nop; io++){
      double f1[3];
      for (int i=0;i<3;i++){
        double s = ops[io].tr[i];
        for (int j=0;j<3;j++){
          s += ops[io].rot[i][j]*f0[j];
        }
        f1[i] = wrap01(s);
      }

      AtomOut out; memset(&out, 0, sizeof(out));
      snprintf(out.symbol, sizeof(out.symbol), "%s", a->symbol);
      out.f[0]=f1[0]; out.f[1]=f1[1]; out.f[2]=f1[2];
      frac_to_cart(cif->cell.tv, out.f, out.r);

      result_add_unique(res, &out, eps);
    }
  }

  free(ops);
  return 1;
}

