  /*========================
    Basis-function DB (OpenMX database Ver. 2019)
    Source: OpenMX manual 3.9, node27, Tables 1-2.
    This is used for --basis=quick|standard|precise.
  ========================*/

  typedef enum {
    BASIS_QUICK = 0,
    BASIS_STANDARD = 1,
    BASIS_PRECISE = 2
  } BasisMode;

  typedef enum {
    COORD_XYZ = 0,   /* Cartesian (Angstrom) */
    COORD_FRAC = 1   /* Fractional */
  } CoordMode;

typedef struct {
  const char *system_name;
  CoordMode coord_mode;
  BasisMode basis_mode;
  int has_kspacing;
  double kspacing;
  int has_energycutoff;
  double energycutoff;
} CIF2OMX_Options;

void cif2omx_options_init(CIF2OMX_Options *opt){
  if (!opt) return;
  opt->system_name = NULL;
  opt->coord_mode = COORD_XYZ;
  opt->basis_mode = BASIS_STANDARD;
  opt->has_kspacing = 0;
  opt->kspacing = CIF2OMX_DEFAULT_KSPACING;
  opt->has_energycutoff = 0;
  opt->energycutoff = CIF2OMX_DEFAULT_ENERGYCUTOFF;
}

static void cif2omx_options_resolve(CIF2OMX_Options *dst, const CIF2OMX_Options *src){
  cif2omx_options_init(dst);
  if (!src) return;
  if (src->system_name) dst->system_name = src->system_name;
  dst->coord_mode = src->coord_mode;
  dst->basis_mode = src->basis_mode;
  dst->has_kspacing = src->has_kspacing;
  dst->kspacing = src->has_kspacing ? src->kspacing : CIF2OMX_DEFAULT_KSPACING;
  dst->has_energycutoff = src->has_energycutoff;
  dst->energycutoff = src->has_energycutoff ? src->energycutoff : CIF2OMX_DEFAULT_ENERGYCUTOFF;
}

