  static const BasisEntry *basis_lookup(const char *vps){
    if (!vps) return NULL;
    /* Linear search is fine here: table is small (<= 100 entries). */
    for (size_t i=0;i<sizeof(g_basis_db)/sizeof(g_basis_db[0]);i++){
      if (strcmp(g_basis_db[i].vps, vps)==0) return &g_basis_db[i];
    }
    return NULL;
  }

  static const char *basis_select_pao(const BasisEntry *e, BasisMode mode){
    if (!e) return NULL;
    switch(mode){
      case BASIS_QUICK:    return e->quick;
      case BASIS_STANDARD: return e->standard;
      case BASIS_PRECISE:  return e->precise;
      default:             return e->standard;
    }
  }

/*========================
  Band.kpath generation
========================*/

#ifndef SQR
#define SQR(x) ((x)*(x))
#endif

enum {
  BRAVAIS_ID_CUB  = 1,
  BRAVAIS_ID_FCC  = 2,
  BRAVAIS_ID_BCC  = 3,
  BRAVAIS_ID_TET  = 4,
  BRAVAIS_ID_BCT  = 5,
  BRAVAIS_ID_ORC  = 6,
  BRAVAIS_ID_ORCF = 7,
  BRAVAIS_ID_ORCI = 8,
  BRAVAIS_ID_HEX  = 9,
  BRAVAIS_ID_ORCC = 10,
  BRAVAIS_ID_RHL  = 11,
  BRAVAIS_ID_MCL  = 12,
  BRAVAIS_ID_MCLC = 13,
  BRAVAIS_ID_TRI  = 14,
  BRAVAIS_ID_NONE = 999
};

typedef struct {
  char name[16];
  char name2[64];
  int id;
  double a, b, c;
  double alpha, beta, gamma;
  double sina, cosa;
} BravaisType;

typedef struct {
  double ks[3];
  double ke[3];
  char labelS[32];
  char labelE[32];
} BandSeg;

typedef struct {
  int nseg;
  BandSeg seg[64];
} BandPath;

static double vec3_len(const double v[3]){
  return sqrt(dot3(v, v));
}

static double vec3_angle_deg(const double a[3], const double b[3]){
  double la = vec3_len(a);
  double lb = vec3_len(b);
  if (la <= 0.0 || lb <= 0.0) return 0.0;
  double x = dot3(a, b)/(la*lb);
  if (x >  1.0) x =  1.0;
  if (x < -1.0) x = -1.0;
  return acos(x)*180.0/M_PI;
}

static void compute_reciprocal_no2pi(const double tv[3][3], double rtv[3][3]){
  double tmp[3];
  double vol;
  cross3(tv[1], tv[2], tmp);
  vol = dot3(tv[0], tmp);
  cross3(tv[1], tv[2], tmp);
  for (int j=0;j<3;j++) rtv[0][j] = tmp[j]/vol;
  cross3(tv[2], tv[0], tmp);
  for (int j=0;j<3;j++) rtv[1][j] = tmp[j]/vol;
  cross3(tv[0], tv[1], tmp);
  for (int j=0;j<3;j++) rtv[2][j] = tmp[j]/vol;
}

static void compute_reciprocal_2pi(const double tv[3][3], double rtv[3][3]){
  compute_reciprocal_no2pi(tv, rtv);
  for (int i=0; i<3; i++) for (int j=0; j<3; j++) rtv[i][j] *= 2.0*M_PI;
}

static void position_internal(const double unit[3][3], const double p[3], double out[3]){
  out[0] = dot3(unit[0], p);
  out[1] = dot3(unit[1], p);
  out[2] = dot3(unit[2], p);
}

static int neareq_eps(double a, double b, double eps){
  return fabs(a-b) < eps;
}

static void bravais_clear(BravaisType *b){
  memset(b, 0, sizeof(*b));
  strcpy(b->name, "NONE");
  strcpy(b->name2, "NONE");
  b->id = BRAVAIS_ID_NONE;
}

static void bravais_set_unit(BravaisType *b, const double unit_conv[3][3]){
  b->a = vec3_len(unit_conv[0]);
  b->b = vec3_len(unit_conv[1]);
  b->c = vec3_len(unit_conv[2]);
  b->alpha = vec3_angle_deg(unit_conv[1], unit_conv[2]);
  b->beta  = vec3_angle_deg(unit_conv[2], unit_conv[0]);
  b->gamma = vec3_angle_deg(unit_conv[0], unit_conv[1]);
  b->sina  = sin(b->alpha*M_PI/180.0);
  b->cosa  = cos(b->alpha*M_PI/180.0);
}

static void bravais_set(BravaisType *b, const char *name, const char *name2, int id){
  snprintf(b->name, sizeof(b->name), "%s", name ? name : "NONE");
  snprintf(b->name2, sizeof(b->name2), "%s", name2 ? name2 : "NONE");
  b->id = id;
}

static BravaisType find_bravais(const double unit_prim[3][3], double eps){
  double recp_prim[3][3];
  double unit_conv[3][3];
  BravaisType bravais;

  compute_reciprocal_no2pi(unit_prim, recp_prim);
  bravais_clear(&bravais);

  /* CUB */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.b, bravais.c, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    bravais_set(&bravais, "CUB", "Cubic", BRAVAIS_ID_CUB);
    return bravais;
  }

  /* FCC */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = -unit_prim[0][i] + unit_prim[1][i] + unit_prim[2][i];
    unit_conv[1][i] = +unit_prim[0][i] - unit_prim[1][i] + unit_prim[2][i];
    unit_conv[2][i] = +unit_prim[0][i] + unit_prim[1][i] - unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.b, bravais.c, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    bravais_set(&bravais, "FCC", "Face-centered cubic", BRAVAIS_ID_FCC);
    return bravais;
  }

  /* BCC */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[1][i] + unit_prim[2][i];
    unit_conv[1][i] = unit_prim[2][i] + unit_prim[0][i];
    unit_conv[2][i] = unit_prim[0][i] + unit_prim[1][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.b, bravais.c, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    bravais_set(&bravais, "BCC", "Body-centered cubic", BRAVAIS_ID_BCC);
    return bravais;
  }

  /* TET */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    bravais_set(&bravais, "TET", "Tetragonal", BRAVAIS_ID_TET);
    return bravais;
  }

  /* BCT */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[1][i] + unit_prim[2][i];
    unit_conv[1][i] = unit_prim[2][i] + unit_prim[0][i];
    unit_conv[2][i] = unit_prim[0][i] + unit_prim[1][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (bravais.c < bravais.a){
      bravais_set(&bravais, "BCT1", "Body-centered tetragonal variation 1", BRAVAIS_ID_BCT);
    } else {
      bravais_set(&bravais, "BCT2", "Body-centered tetragonal variation 2", BRAVAIS_ID_BCT);
    }
    return bravais;
  }

  /* ORC */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.a < bravais.b && bravais.b < bravais.c)) return bravais;
    bravais_set(&bravais, "ORC", "Orthorhombic", BRAVAIS_ID_ORC);
    return bravais;
  }

  /* ORCF */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = -unit_prim[0][i] + unit_prim[1][i] + unit_prim[2][i];
    unit_conv[1][i] = +unit_prim[0][i] - unit_prim[1][i] + unit_prim[2][i];
    unit_conv[2][i] = +unit_prim[0][i] + unit_prim[1][i] - unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.a < bravais.b && bravais.b < bravais.c)) return bravais;
    double ka2 = 1.0/SQR(bravais.a);
    double kb2 = 1.0/SQR(bravais.b);
    double kc2 = 1.0/SQR(bravais.c);
    if (neareq_eps(ka2, kb2+kc2, eps)){
      bravais_set(&bravais, "ORCF3", "Face-centered orthorhombic variation 3", BRAVAIS_ID_ORCF);
    } else if (ka2 > kb2+kc2){
      bravais_set(&bravais, "ORCF1", "Face-centered orthorhombic variation 1", BRAVAIS_ID_ORCF);
    } else {
      bravais_set(&bravais, "ORCF2", "Face-centered orthorhombic variation 2", BRAVAIS_ID_ORCF);
    }
    return bravais;
  }

  /* ORCI */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[1][i] + unit_prim[2][i];
    unit_conv[1][i] = unit_prim[2][i] + unit_prim[0][i];
    unit_conv[2][i] = unit_prim[0][i] + unit_prim[1][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.a < bravais.b && bravais.b < bravais.c)) return bravais;
    bravais_set(&bravais, "ORCI", "Body-centered orthorhombic", BRAVAIS_ID_ORCI);
    return bravais;
  }

  /* HEX */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 120.0, eps)){
    bravais_set(&bravais, "HEX", "Hexagnal", BRAVAIS_ID_HEX);
    return bravais;
  }

  /* ORCC */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[1][i] + unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i] - unit_prim[0][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.alpha, 90.0, eps) &&
      neareq_eps(bravais.beta , 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.a < bravais.b)) return bravais;
    bravais_set(&bravais, "ORCC", "Base-centered orthorhombic", BRAVAIS_ID_ORCC);
    return bravais;
  }

  /* RHL */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.a, bravais.b, eps) &&
      neareq_eps(bravais.b, bravais.c, eps) &&
      neareq_eps(bravais.alpha, bravais.beta, eps) &&
      neareq_eps(bravais.beta , bravais.gamma, eps)){
    if (bravais.alpha < 90.0){
      bravais_set(&bravais, "RHL1", "Rhombohedral variation 1", BRAVAIS_ID_RHL);
    } else {
      bravais_set(&bravais, "RHL2", "Rhombohedral variation 2", BRAVAIS_ID_RHL);
    }
    return bravais;
  }

  /* MCL */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.beta, 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.alpha < 90.0)) return bravais;
    bravais_set(&bravais, "MCL", "Monoclinic", BRAVAIS_ID_MCL);
    return bravais;
  }

  /* MCLC */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i] - unit_prim[1][i];
    unit_conv[1][i] = unit_prim[0][i] + unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  if (neareq_eps(bravais.beta, 90.0, eps) &&
      neareq_eps(bravais.gamma, 90.0, eps)){
    if (!(bravais.alpha < 90.0)) return bravais;
    double kgamma = vec3_angle_deg(recp_prim[0], recp_prim[1]);
    if (neareq_eps(kgamma, 90.0, eps)){
      bravais_set(&bravais, "MCLC2", "Base-centered monoclinic variation 2", BRAVAIS_ID_MCLC);
    } else if (kgamma > 90.0){
      bravais_set(&bravais, "MCLC1", "Base-centered monoclinic variation 1", BRAVAIS_ID_MCLC);
    } else {
      double t = bravais.b/bravais.c*bravais.cosa + SQR(bravais.b)/SQR(bravais.a)*SQR(bravais.sina);
      if (neareq_eps(t, 1.0, eps)){
        bravais_set(&bravais, "MCLC4", "Base-centered monoclinic variation 4", BRAVAIS_ID_MCLC);
      } else if (t < 1.0){
        bravais_set(&bravais, "MCLC3", "Base-centered monoclinic variation 3", BRAVAIS_ID_MCLC);
      } else {
        bravais_set(&bravais, "MCLC5", "Base-centered monoclinic variation 5", BRAVAIS_ID_MCLC);
      }
    }
    return bravais;
  }

  /* TRI */
  for (int i=0;i<3;i++){
    unit_conv[0][i] = unit_prim[0][i];
    unit_conv[1][i] = unit_prim[1][i];
    unit_conv[2][i] = unit_prim[2][i];
  }
  bravais_set_unit(&bravais, (const double (*)[3])unit_conv);
  {
    double kgamma = vec3_angle_deg(recp_prim[0], recp_prim[1]);
    double kalpha = vec3_angle_deg(recp_prim[1], recp_prim[2]);
    double kbeta  = vec3_angle_deg(recp_prim[2], recp_prim[0]);
    if (kalpha > 90.0 && kbeta > 90.0 && neareq_eps(kgamma, 90.0, eps)){
      bravais_set(&bravais, "TRI2a", "Triclinic variation 2a", BRAVAIS_ID_TRI);
      return bravais;
    } else if (kalpha < 90.0 && kbeta < 90.0 && neareq_eps(kgamma, 90.0, eps)){
      bravais_set(&bravais, "TRI2b", "Triclinic variation 2b", BRAVAIS_ID_TRI);
      return bravais;
    } else if (kalpha > 90.0 && kbeta > 90.0 && kgamma > 90.0 &&
               kalpha >= kgamma && kbeta >= kgamma){
      bravais_set(&bravais, "TRI1a", "Triclinic variation 1a", BRAVAIS_ID_TRI);
      return bravais;
    } else if (kalpha < 90.0 && kbeta < 90.0 && kgamma < 90.0 &&
               kalpha <= kgamma && kbeta <= kgamma){
      bravais_set(&bravais, "TRI1b", "Triclinic variation 1b", BRAVAIS_ID_TRI);
      return bravais;
    }
  }

  return bravais;
}

static void band_path_init(BandPath *path){
  memset(path, 0, sizeof(*path));
}

static void add_band_segment(BandPath *path, const double ks[3], const char *labelS,
                             const double ke[3], const char *labelE){
  if (!path || path->nseg >= (int)(sizeof(path->seg)/sizeof(path->seg[0]))) return;
  BandSeg *s = &path->seg[path->nseg++];
  for (int i=0;i<3;i++){
    s->ks[i] = ks[i];
    s->ke[i] = ke[i];
  }
  snprintf(s->labelS, sizeof(s->labelS), "%s", labelS ? labelS : "");
  snprintf(s->labelE, sizeof(s->labelE), "%s", labelE ? labelE : "");
}

