    (void)Z;
    add_band_segment(path, G, "G", Y, "Y");
    add_band_segment(path, Y, "Y", C, "C");
    add_band_segment(path, C, "C", D, "D");
    add_band_segment(path, D, "D", X, "X");
    add_band_segment(path, X, "X", G, "G");
    add_band_segment(path, G, "G", Z, "Z");
    add_band_segment(path, Z, "Z", D1, "D1");
    add_band_segment(path, D1, "D1", H, "H");
