    const double A1[3] = { 1.0/2.0, 1.0/2.0-ze, 1-ze }; /* A1 */
    (void)A1;
    const double L[3] = { 1.0/2.0, 1.0/2.0, 1.0/2.0 }; /* L */
    (void)L;
    const double T[3] = { 1, 1.0/2.0, 1.0/2.0 }; /* T */
    (void)T;
    const double X[3] = { 0, et, et }; /* X */
    (void)X;
    const double X1[3] = { 1, 1-et, 1-et }; /* X1 */
    (void)X1;
    const double Y[3] = { 1.0/2.0, 0, 1.0/2.0 }; /* Y */
    (void)Y;
    const double Z[3] = { 1.0/2.0, 1.0/2.0, 0 }; /* Z */
    (void)Z;
    add_band_segment(path, G, "G", Y, "Y");
    add_band_segment(path, Y, "Y", T, "T");
    add_band_segment(path, T, "T", Z, "Z");
    add_band_segment(path, Z, "Z", G, "G");
    add_band_segment(path, G, "G", X, "X");
    add_band_segment(path, X, "X", A1, "A1");
