#ifdef CIF2OPENMX_MAIN
static void print_usage_fp(FILE *fp, const char *prog){
  fprintf(fp,
    "Usage: %s input.cif [options]\n"
    "       %s --help\n"
    "\n"
    "Options (placed after input.cif):\n"
    "  -o, --output FILE        Output OpenMX input (default: stdout)\n"
    "  -c, --coord MODE         Coordinate mode: xyz | fractional (default: xyz)\n"
    "  -b, --basis MODE         Basis quality: quick | standard | precise\n"
    "                           (default: standard)\n"
    "  -n, --name NAME          System.Name value (default: input filename stem)\n"
    "  -k, --kspacing D         Set scf.Kgrid from reciprocal-space spacing D (1/Ang).\n"
    "                           Uses reciprocal vectors including 2*pi and\n"
    "                           Nk_i = floor(|b_i|/D), clipped to >= 1.\n"
    "                           Default: D = 0.33 (matches OpenMX Viewer).\n"
    "                           Example: -k 0.33\n"
    "  -e, --ecut HA            Set scf.energycutoff to HA as-is.\n"
    "                           If omitted, the default value 220.0 is used.\n"
    "                           Example: -e 100 writes scf.energycutoff 100.0\n"
    "  -h, --help               Show this help\n"
    "\n"
    "If input.cif is omitted, this help is printed to standard output.\n",
    prog, prog);
}

static void print_usage(const char *prog){
  print_usage_fp(stderr, prog);
}

static int parse_coord_mode(const char *s, CoordMode *out){
  if (!s || !out) return 0;
  if (strcmp(s,"xyz")==0) { *out = COORD_XYZ; return 1; }
  if (strcmp(s,"fractional")==0 || strcmp(s,"frac")==0) { *out = COORD_FRAC; return 1; }
  return 0;
}

static int parse_basis_mode(const char *s, BasisMode *out){
  if (!s || !out) return 0;
  if (strcmp(s,"quick")==0) { *out = BASIS_QUICK; return 1; }
  if (strcmp(s,"standard")==0) { *out = BASIS_STANDARD; return 1; }
  if (strcmp(s,"precise")==0) { *out = BASIS_PRECISE; return 1; }
  return 0;
}

static int parse_positive_double(const char *s, double *out){
  if (!s || !out) return 0;
  char *end = NULL;
  double v = strtod(s, &end);
  if (end == s || *end != '\0' || !(v > 0.0)) return 0;
  *out = v;
  return 1;
}

static char *stem_from_path(const char *path){
  if (!path || !*path) return xstrdup("cif_structure");
  /* Treat '-' as stdin */
  if (strcmp(path, "-") == 0) return xstrdup("stdin");

  const char *base = path;
  /* Handle both Unix '/' and Windows '\\' */
  for (const char *p = path; *p; ++p){
    if (*p == '/' || *p == '\\') base = p + 1;
  }
  /* Copy base */
  char *s = xstrdup(base);
  /* Strip extension: remove last '.' if it is not the first char */
  char *dot = strrchr(s, '.');
  if (dot && dot != s){
    *dot = '\0';
  }
  /* Fallback if empty */
  if (s[0] == '\0'){
    free(s);
    return xstrdup("cif_structure");
  }
  return s;
}

int main(int argc, char **argv){
  const char *out_path = NULL;
  const char *in_path = NULL;
  char *sys_name_alloc = NULL;
  char **opt_argv = NULL;
  CIF2OMX_Options opt;

  cif2omx_options_init(&opt);

  static const struct option long_opts[] = {
    {"output",   required_argument, 0, 'o'},
    {"coord",    required_argument, 0, 'c'},
    {"basis",    required_argument, 0, 'b'},
    {"name",     required_argument, 0, 'n'},
    {"kspacing", required_argument, 0, 'k'},
    {"kmesh",    required_argument, 0, 'k'}, /* backward-compatible alias */
    {"ecut",     required_argument, 0, 'e'},
    {"help",     no_argument,       0, 'h'},
    {0,0,0,0}
  };

  if (argc == 1){
    print_usage_fp(stdout, argv[0]);
    return 0;
  }

  if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0){
    print_usage_fp(stdout, argv[0]);
    return 0;
  }

  in_path = argv[1];
  if (strcmp(in_path, "-") != 0 && in_path[0] == '-'){
    fprintf(stderr, "Error: input.cif must be the first argument.\n");
    print_usage(argv[0]);
    return 2;
  }

  {
    int opt_argc = argc - 1;
    opt_argv = (char**)xmalloc((size_t)(opt_argc + 1) * sizeof(char*));
    opt_argv[0] = argv[0];
    for (int i=2; i<argc; i++) opt_argv[i-1] = argv[i];
    opt_argv[opt_argc] = NULL;

    optind = 1;
    opterr = 0;

    int optch;
    while ((optch = getopt_long(opt_argc, opt_argv, "o:c:b:n:k:e:h", long_opts, NULL)) != -1){
      switch (optch){
        case 'o':
          out_path = optarg;
          break;
        case 'c':
          if (!parse_coord_mode(optarg, &opt.coord_mode)){
            fprintf(stderr, "Error: invalid --coord '%s'\n", optarg);
            print_usage(argv[0]);
            free(opt_argv);
            return 2;
          }
          break;
        case 'b':
          if (!parse_basis_mode(optarg, &opt.basis_mode)){
            fprintf(stderr, "Error: invalid --basis '%s'\n", optarg);
            print_usage(argv[0]);
            free(opt_argv);
            return 2;
          }
          break;
        case 'n':
          opt.system_name = optarg;
          break;
        case 'k':
          if (!parse_positive_double(optarg, &opt.kspacing)){
            fprintf(stderr, "Error: invalid --kspacing '%s'\n", optarg);
            print_usage(argv[0]);
            free(opt_argv);
            return 2;
          }
          opt.has_kspacing = 1;
          break;
        case 'e':
          if (!parse_positive_double(optarg, &opt.energycutoff)){
            fprintf(stderr, "Error: invalid --ecut '%s'\n", optarg);
            print_usage(argv[0]);
            free(opt_argv);
            return 2;
          }
          opt.has_energycutoff = 1;
          break;
        case 'h':
          print_usage_fp(stdout, argv[0]);
          free(opt_argv);
          return 0;
        default:
          print_usage(argv[0]);
          free(opt_argv);
          return 2;
      }
    }

    if (optind < opt_argc){
      fprintf(stderr, "Error: unexpected positional argument '%s' after options.\n", opt_argv[optind]);
      print_usage(argv[0]);
      free(opt_argv);
      return 2;
    }
  }

  if (!opt.system_name){
    sys_name_alloc = stem_from_path(in_path);
    opt.system_name = sys_name_alloc;
  }

  FILE *fp = stdin;
  if (strcmp(in_path, "-") != 0){
    fp = fopen(in_path, "rb");
    if (!fp){
      perror("open input");
      if (opt_argv) free(opt_argv);
      if (sys_name_alloc) free(sys_name_alloc);
      return 1;
    }
  }

  FILE *fo = stdout;
  if (out_path){
    fo = fopen(out_path, "wb");
    if (!fo){
      perror("open output");
      if (fp != stdin) fclose(fp);
      if (opt_argv) free(opt_argv);
      if (sys_name_alloc) free(sys_name_alloc);
      return 1;
    }
  }

  CIF_Result res;
  if (!cif_fp_to_openmx_opt(fp, fo, &res, &opt)){
    fprintf(stderr, "Failed.\n");
    if (fp != stdin) fclose(fp);
    if (fo != stdout) fclose(fo);
    if (opt_argv) free(opt_argv);
    if (sys_name_alloc) free(sys_name_alloc);
    return 1;
  }

  fprintf(stderr, "Parsed %d atoms.\n", res.n);
  cif_result_free(&res);

  if (fp != stdin) fclose(fp);
  if (fo != stdout) fclose(fo);
  if (opt_argv) free(opt_argv);
  if (sys_name_alloc) free(sys_name_alloc);
  return 0;
}
#endif
